class Solution {
    private static final int MOD = (int) 1e9 + 7;
    public int countVowelPermutation(int n) {
        long[] dp = new long[5];
        dp[0] = dp[1] = dp[2] = dp[3] = dp[4] = 1;
        for (int i = 2; i <= n; i++) {
            long[] next = new long[5];
            next[0] = (dp[1] + dp[2] + dp[4]) % MOD;
            next[1] = (dp[0] + dp[2]) % MOD;
            next[2] = (dp[0] + dp[1] + dp[3]) % MOD;
            next[3] = (dp[2]) % MOD;
            next[4] = (dp[0] + dp[2]) % MOD;
            dp = next;
        }
        return (int)((dp[0] + dp[1] + dp[2] + dp[3] + dp[4]) % MOD);
    }
}
